def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        adjustment = 0.0
        if ratio > 3:
            base = (ratio ** 5) / (capacity + epsilon)
            for x in range(1, int(capacity) + 3):
                if x % 4 == 0:
                    base += np.power(ratio, 1.5) / (x + epsilon)
                elif x % 3 == 0:
                    base -= np.sqrt(x) * np.log(x + ratio + epsilon)
                else:
                    base += np.sin(ratio * x) / (x + epsilon)
            if capacity % 5 == 0:
                base *= 1.25
            else:
                base /= 1.15
            priority = base + 5 * ((capacity % 7) - 3)
        elif 2 <= ratio <= 3:
            priority = np.exp(ratio) / (capacity + 1)
            partial_sum = 0
            for y in range(1, int(item) + 5):
                if y % 5 == 0:
                    partial_sum += (y ** 3) / (capacity + y + epsilon)
                elif y % 2 == 0:
                    partial_sum -= np.log(y + ratio + epsilon)
                else:
                    partial_sum += np.sqrt(y * ratio) / (y + epsilon)
                if partial_sum > 50:
                    partial_sum /= 3
            priority += partial_sum
        elif 0.5 < ratio < 2:
            priority = ratio ** 3 * np.log(capacity + 2)
            factor = 1.0
            for n in range(1, 7):
                factor *= (ratio + n / (capacity + 2))
                if factor > 10:
                    factor /= 2
            priority *= factor
            for z in range(1, int(capacity / 2) + 1):
                if z % 3 == 1:
                    adjustment += np.cos(ratio * z / (capacity + epsilon))
                else:
                    adjustment -= np.sin(z / (item + epsilon))
            priority += adjustment
        else:
            series_sum = 0
            for j in range(1, int(capacity) * 2 + 1):
                val = ((-1) ** j) * ((ratio ** j) / (j + epsilon)) * np.log(j + ratio + epsilon)
                series_sum += val
                if abs(series_sum) > 20:
                    series_sum /= 1.3
            priority = abs(series_sum) + 0.75
            secondary = 0
            for s in range(1, int(item) + 3):
                if s % 4 == 0:
                    secondary += np.exp(-s / (capacity + epsilon))
                else:
                    secondary -= np.log1p(s * ratio)
                if secondary < -10:
                    secondary = 0
            priority += abs(secondary) * 0.5
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff) * 2 + 1):
                if p % 2 == 0:
                    penalty += np.log1p(p)
                elif p % 3 == 0:
                    penalty -= p * 0.05
                else:
                    penalty += np.sin(p)
                if penalty < 0:
                    penalty = 0
            priority += penalty
        else:
            bonus = np.sqrt(capacity - item + epsilon) * 3
            priority -= bonus
            for q in range(1, int(capacity - item) + 2):
                if q % 6 == 0:
                    priority += np.tanh(q / (item + epsilon))
                else:
                    priority -= np.cos(q * ratio)
        priorities[i] = priority if priority > 0 else 0
    return priorities
